(() => {
  const eventosAgendados = $json.data;
  const disponibilidadeSemanal = $('Configurar Agenda Semanal').first().json;
  const intervaloSemanas = 12;
  const intervaloMinutos = $('Configurar Agenda Semanal').first().json['timeBetweenMeetingsMinutes '];
  const dayMap = { 0: "DOM", 1: "SEG", 2: "TER", 3: "QUA", 4: "QUI", 5: "SEX", 6: "SAB" };
  function getDateWithTime(date, timeStr) { if (!timeStr) return null; const [hour, minute] = timeStr.split(":").map(Number); const newDate = new Date(date); newDate.setHours(hour, minute, 0, 0); return newDate; }
  function formatTime(date) { return date.getHours().toString().padStart(2, '0') + ':' + date.getMinutes().toString().padStart(2, '0'); }
  function saoMesmoDia(d1, d2) { return d1.getFullYear()===d2.getFullYear() && d1.getMonth()===d2.getMonth() && d1.getDate()===d2.getDate(); }
  function gerarHorariosDisponiveis() {
    const horariosDisponiveis = []; const hoje = new Date();
    const eventosValidos = Array.isArray(eventosAgendados) ? eventosAgendados.filter(e => e?.start?.dateTime && e?.end?.dateTime) : [];
    for (let i = 0; i < intervaloSemanas * 7; i++) {
      const dataAtual = new Date(hoje); dataAtual.setDate(hoje.getDate() + i); dataAtual.setHours(0, 0, 0, 0);
      const diaSemana = dayMap[dataAtual.getDay()]; const configDia = disponibilidadeSemanal.schedule.find(d => d.day === diaSemana);
      if (!configDia || !configDia.available) continue;
      const inicioJanela = getDateWithTime(dataAtual, configDia.hours.after); const fimJanela = getDateWithTime(dataAtual, configDia.hours.before);
      if (!inicioJanela || !fimJanela) continue;
      const eventosDoDia = eventosValidos.filter(e => saoMesmoDia(new Date(e.start.dateTime), dataAtual));
      for (let slotInicio = new Date(inicioJanela); slotInicio < fimJanela; ) {
        const slotFim = new Date(slotInicio.getTime() + intervaloMinutos * 60000); if (slotFim > fimJanela) break;
        let conflita = eventosValidos.length > 0 && eventosDoDia.some(e => { const ie = new Date(e.start.dateTime); const fe = new Date(e.end.dateTime); return slotInicio < fe && slotFim > ie; });
        if (!conflita) horariosDisponiveis.push({ data: slotInicio.toISOString().split('T')[0], start: formatTime(slotInicio), end: formatTime(slotFim) });
        slotInicio = new Date(slotFim);
      }
    }
    return horariosDisponiveis;
  }
  try { return JSON.stringify(gerarHorariosDisponiveis()); } catch (error) { return JSON.stringify({ error: error.message }); }
})()

}}

parameters.jsCode:
const items = $input.first().json;
let data;
try { data = typeof items.data === 'string' ? JSON.parse(items.data) : items.data; } catch (e) { return [{ json: { disponibilidade: 'Erro ao processar horários disponíveis.' } }]; }
if (!Array.isArray(data) || data.length === 0) return [{ json: { disponibilidade: 'Não há horários disponíveis no momento.' } }];
const days = ['domingo', 'segunda-feira', 'terça-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sábado'];
const grouped = {};
for (const slot of data) { if (!grouped[slot.data]) grouped[slot.data] = []; grouped[slot.data].push(slot.start.replace(':00', 'h').replace(':30', 'h30')); }
let result = '';
const dates = Object.keys(grouped).slice(0, 14);
for (const dateStr of dates) { const parts = dateStr.split('-'); const date = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]), 12, 0, 0); const dayName = days[date.getDay()]; const formattedDate = `${parts[2]}/${parts[1]}`; const horarios = grouped[dateStr].slice(0, 8).join(', '); result += `${dayName} ${formattedDate}: ${horarios}\n`; }
return [{ json: { disponibilidade: result.trim() } }];

